import axios, { AxiosInstance, AxiosRequestConfig } from 'axios'
import type { 
  Iteration, 
  AgentState, 
  SystemOverview, 
  SystemMetrics,
  PaginatedResponse 
} from '@/types'

const BASE_URL = import.meta.env.VITE_API_BASE_URL || 'http://localhost:3000/api'

class APIClient {
  private client: AxiosInstance

  constructor() {
    this.client = axios.create({
      baseURL: BASE_URL,
      timeout: 30000,
      headers: {
        'Content-Type': 'application/json'
      }
    })

    this.client.interceptors.response.use(
      response => response.data,
      error => {
        console.error('API Error:', error)
        throw error
      }
    )
  }

  // 迭代相关
  async getIterations(params?: {
    page?: number
    pageSize?: number
    status?: string
  }): Promise<PaginatedResponse<Iteration>> {
    return this.client.get('/iterations', { params })
  }

  async getCurrentIteration(): Promise<Iteration | null> {
    return this.client.get('/iterations/current')
  }

  async getIterationDetail(id: number): Promise<Iteration> {
    return this.client.get(`/iterations/${id}`)
  }

  // Agent 相关
  async getAgents(): Promise<AgentState[]> {
    return this.client.get('/agents')
  }

  async getActiveAgents(): Promise<AgentState[]> {
    return this.client.get('/agents/active')
  }

  async getAgentPerformance(): Promise<any> {
    return this.client.get('/agents/stats/performance')
  }

  // 系统相关
  async getSystemOverview(): Promise<SystemOverview> {
    return this.client.get('/system/overview')
  }

  async getSystemMetrics(): Promise<SystemMetrics[]> {
    return this.client.get('/system/metrics')
  }

  async getHealthStatus(): Promise<any> {
    return this.client.get('/system/health')
  }
}

export const api = new APIClient()
