import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import { api } from '@/api'
import type { Iteration } from '@/types'

export const useIterationStore = defineStore('iteration', () => {
  const iterations = ref<Iteration[]>([])
  const currentIteration = ref<Iteration | null>(null)
  const loading = ref(false)
  const logs = ref<any[]>([])

  const totalIterations = computed(() => iterations.value.length)
  const runningIterations = computed(() => 
    iterations.value.filter(i => i.status === 'running').length
  )
  const completedIterations = computed(() => 
    iterations.value.filter(i => i.status === 'completed').length
  )
  const failedIterations = computed(() => 
    iterations.value.filter(i => i.status === 'failed').length
  )

  async function fetchIterations(params?: {
    page?: number
    pageSize?: number
    status?: string
  }) {
    loading.value = true
    try {
      const response = await api.getIterations(params)
      iterations.value = response.data || []
    } catch (error) {
      console.error('Failed to fetch iterations:', error)
    } finally {
      loading.value = false
    }
  }

  async function fetchCurrentIteration() {
    try {
      currentIteration.value = await api.getCurrentIteration()
    } catch (error) {
      console.error('Failed to fetch current iteration:', error)
    }
  }

  function updateIteration(iteration: Iteration) {
    const index = iterations.value.findIndex(i => i.id === iteration.id)
    if (index !== -1) {
      iterations.value[index] = iteration
    } else {
      iterations.value.unshift(iteration)
    }

    // 更新当前迭代
    if (iteration.status === 'running') {
      currentIteration.value = iteration
    } else if (currentIteration.value?.id === iteration.id) {
      currentIteration.value = null
    }
  }

  function updateProgress(progress: number) {
    if (currentIteration.value) {
      currentIteration.value.progress = progress
    }
  }

  function addLog(log: any) {
    logs.value.push(log)
    // 保持最多1000条日志
    if (logs.value.length > 1000) {
      logs.value = logs.value.slice(-1000)
    }
  }

  return {
    iterations,
    currentIteration,
    loading,
    logs,
    totalIterations,
    runningIterations,
    completedIterations,
    failedIterations,
    fetchIterations,
    fetchCurrentIteration,
    updateIteration,
    updateProgress,
    addLog
  }
})
```

