// src/stores/agent.ts
import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import type { AgentData } from '@/types'

export const useAgentStore = defineStore('agent', () => {
  const agents = ref<Record<string, AgentData>>({})
  const loading = ref(false)

  // 初始化 10 个 Agent
  const agentTypes = [
    'product_manager',
    'architect', 
    'ui_designer',
    'frontend',
    'backend',
    'database',
    'tester',
    'security',
    'documenter',
    'assets'
  ]

  function initializeAgents() {
    agentTypes.forEach(type => {
      agents.value[type] = {
        name: type,
        status: 'idle',
        progress: 0,
        currentTask: '',
        executionCount: 0,
        successCount: 0,
        avgExecutionTime: 0
      }
    })
  }

  // 更新 Agent 状态
  function updateAgent(name: string, data: Partial<AgentData>) {
    if (agents.value[name]) {
      agents.value[name] = { ...agents.value[name], ...data }
    }
  }

  // 批量更新
  function updateAgents(data: Record<string, AgentData>) {
    agents.value = { ...agents.value, ...data }
  }

  // 获取运行中的 Agent
  const runningAgents = computed(() => {
    return Object.values(agents.value).filter(a => a.status === 'running')
  })

  // 获取活跃 Agent 数量
  const activeCount = computed(() => {
    return Object.values(agents.value).filter(a => 
      a.status === 'running' || a.status === 'idle'
    ).length
  })

  return {
    agents,
    loading,
    runningAgents,
    activeCount,
    initializeAgents,
    updateAgent,
    updateAgents
  }
})
